import{_ as t,o as a,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"18. Part Time Employment","description":"","frontmatter":{"title":"18. Part Time Employment","eba":"Doctors in Training 2022-2026","topics":["leave","hours","overtime","shift-work"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/18-part-time-employment.md","filePath":"ebas/doctors-in-training/doctor-employment/18-part-time-employment.md"}'),i={name:"ebas/doctors-in-training/doctor-employment/18-part-time-employment.md"};function n(s,e,m,l,p,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_18-part-time-employment" tabindex="-1">18. Part Time Employment <a class="header-anchor" href="#_18-part-time-employment" aria-label="Permalink to &quot;18. Part Time Employment&quot;">​</a></h1><p><strong>18.1</strong> Part-time means a Doctor who is ready, willing and available to work on a regular basis any number of hours less than the ordinary hours of work prescribed in <a href="/eba/ebas/doctors-in-training/doctor-employment/17-full-time-employment.html">clause 17</a>.</p><p><strong>18.2</strong> The number of hours worked by a part-time Doctor may vary from week to week by mutual agreement.</p><p><strong>18.3</strong> A part-time HMO, MO and SMO will be paid an hourly rate equal to 1/38th of the weekly salary for the Doctor’s classification.</p><p><strong>18.4</strong> A part-time Registrar will be paid an hourly rate equal to 1/43rd of the weekly salary for the Doctor’s classification. A Registrar will also receive Training Time in accordance with clause 34 (Training Time) on a pro-rata basis having regard to their part-time fraction.</p><p>Example: A part-time Registrar engaged on a 0.5 EFT contract will receive 2.5 hours Training Time per week.</p><p><strong>18.5</strong> Where expressly provided, a part-time Doctor is entitled to be paid for penalties and allowances on a pro-rata basis.</p><p><strong>18.6</strong> Where a part-time Doctor has an entitlement to leave under this Agreement, the part-time Employee will be paid according to the number of hours the Employee would have worked on the day/s on which the leave was taken.</p><p>Plain language terms: part-time, PT.</p>',9)])])}const g=t(i,[["render",n]]);export{h as __pageData,g as default};
